_STORE_ROOT = Path.home() / ".ihui"
_SWARMS_DIR = _STORE_ROOT / "swarms"


def _ensure_dirs() -> None:
    """确保存储目录存在。"""
    _SWARMS_DIR.mkdir(parents=True, exist_ok=True)


# ---------------------------------------------------------------------------
# 数据结构
