class SwarmAgentRole(str, Enum):
    """Swarm 中 Agent 的角色。"""
    COORDINATOR = "coordinator"  # 协调者: 分析任务 + 分解子任务
    WORKER = "worker"            # 工作者: 执行具体工作
    REVIEWER = "reviewer"        # 审查者: 审查工作结果


